import{z as e}from"./chunks/theme.C49JthOR.js";import{u as l}from"./chunks/link-icons.BeUxiLwc.js";import{a3 as n,o as i,c as s,ah as r}from"./chunks/framework.cbxun9lb.js";const y=JSON.parse('{"title":"Obsidian WebDAV Sync","titleTemplate":"面向 Obsidian 的 WebDAV 同步插件","description":"WebDAV Sync 是一款为 Obsidian 设计的插件，用于将您的仓库与 WebDAV 服务器同步。它在可靠的双向同步、更好的性能以及无厂商锁定方面优于现有解决方案。","frontmatter":{"layout":"project","title":"Obsidian WebDAV Sync","titleTemplate":"面向 Obsidian 的 WebDAV 同步插件","description":"WebDAV Sync 是一款为 Obsidian 设计的插件，用于将您的仓库与 WebDAV 服务器同步。它在可靠的双向同步、更好的性能以及无厂商锁定方面优于现有解决方案。","logo":"https://github.com/hesprs/obsidian-webdav-sync/raw/main/assets/logo.svg","links":[{"name":"GitHub 仓库","url":"https://github.com/hesprs/obsidian-webdav-sync","color":"#010409"}],"head":[["meta",{"name":"keywords","content":"Obsidian, Obsidian 插件, Obsidian WebDAV Sync, Obsidian WebDAV, WebDAV 同步, 跨设备同步"}]]},"headers":[],"relativePath":"zh-Hans/projects/obsidian-webdav-sync.md","filePath":"zh-Hans/projects/obsidian-webdav-sync.md","lastUpdated":1777202603000}'),a={name:"zh-Hans/projects/obsidian-webdav-sync.md"},x=n({...a,setup(d){return l({"GitHub 仓库":e}),(o,t)=>(i(),s("div",null,[...t[0]||(t[0]=[r('<h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to “简介”">​</a></h2><p>Obsidian WebDAV Sync 是一款面向 Obsidian 的通用型双向 WebDAV 同步插件。由于当前没有单一插件能够可靠且便捷地将仓库与 WebDAV 服务器同步，因此开发了此插件。它在可靠双向同步、更好的性能以及无厂商锁定方面优于现有方案：</p><ul><li><p>🔄 <strong>可靠的双向同步</strong>：</p><ul><li>插件可将您的仓库与 WebDAV 存储同步。</li><li>通过三方比较：远程状态、本地状态，以及上一次同步记录中的本地/远程状态。</li><li>再依据决策矩阵以获得最高精度与数据完整性，详情见<a href="#技术架构解析">下方</a>。</li></ul></li><li><p>🔀 <strong>自动同步与冲突处理</strong>：</p><ul><li>插件支持以下自动触发的同步方式： <ul><li><strong>启动同步</strong>：在 Obsidian 启动时触发同步。</li><li><strong>定时同步</strong>：按固定周期触发同步。</li><li><strong>实时同步</strong>：检测到变更后立即触发同步。</li></ul></li><li>插件支持以下冲突处理方式：</li><li>智能合并 (Smart merge)</li><li>保留最新版本 (Latest survive)</li><li>使用远程版本 (Use remote)</li><li>使用本地版本 (Use local)</li><li>跳过 (Skip)</li></ul></li><li><p>⚡ <strong>极致性能</strong>：</p><ul><li>大多数同步操作通过并行化网络请求完成。</li><li>实时同步默认使用缓存的远程状态，因此通常可在数秒内完成。</li><li>体积比 Remotely Save <strong>小 10 倍</strong>，启动加载时间 <strong>快 8 倍</strong>。</li></ul></li><li><p>🧰 <strong>细粒度配置</strong>：</p><ul><li>用户可调整多项参数以适配不同服务： <ul><li><strong>最大并发 WebDAV 请求数</strong>：应对服务限流。</li><li><strong>WebDAV 请求最小间隔</strong>：应对服务限流。</li><li><strong>跳过大文件</strong>：应对存储空间不足。</li><li><strong>最大并发同步任务数</strong>：控制 CPU 与磁盘占用。</li><li><strong>最大并发吞吐量</strong>：控制内存占用并避免崩溃。</li></ul></li></ul></li><li><p>📦 <strong>生产级可扩展性</strong>：</p><ul><li>可平稳处理超过 3000 个文件的仓库。</li><li>负载均衡与分块下载可让插件一次处理 GB 级数据。</li><li>大文件下载支持断点续传。</li></ul></li><li><p>🎨 <strong>优秀的 UI 与可观测性</strong>：</p><ul><li>通过四种方式（弹窗、状态栏、通知、日志）持续展示同步进度。</li><li>文件变更会以文件树形式呈现，便于精细选择性同步。</li><li>日志工具会输出可读性良好的 Markdown 文档。</li></ul></li></ul><h2 id="为何需要另一款同步插件" tabindex="-1">为何需要另一款同步插件？ <a class="header-anchor" href="#为何需要另一款同步插件" aria-label="Permalink to “为何需要另一款同步插件？”">​</a></h2><p>作为一名需要在多设备间工作的 Obsidian 用户，我亲身经历了同步困境：寻找一款既可靠灵活，又不牺牲数据完整性的方案。在尝试了社区中几乎所有同步插件后，我发现它们都存在各种权衡，严重影响了我的日常工作效率：</p><ul><li><strong>Remotely Save</strong>：功能全面，但存在维护停滞和 Bug 问题——例如已删除的文件会神秘重现（这正是我弃用它的主要原因）。</li><li><strong>Syncthing Integration</strong>：提供了优秀的 P2P 同步体验，但要求所有设备必须同时在线。</li><li><strong>Live Sync</strong>：虽然稳健，但代价是复杂的服务器搭建流程。</li><li><strong>基于 Git 的方案</strong>：在版本控制方面表现出色，但并不适合无缝的日常同步。</li></ul><p>随后，我发现了 <a href="https://github.com/nutstore/obsidian-nutstore-sync" target="_blank" rel="noreferrer">Nutstore Sync</a> —— 一款优秀的插件，但仅专为 Nutstore 设计。我想：为什么不将其打造为通用型工具呢？于是我将其 Fork，并进行了大规模重构，以消除厂商锁定、提升性能并增强稳定性。最终诞生的成果就是 <strong>Obsidian WebDAV Sync</strong>。</p><h2 id="技术架构解析" tabindex="-1">技术架构解析 <a class="header-anchor" href="#技术架构解析" aria-label="Permalink to “技术架构解析”">​</a></h2><p>将 Obsidian 仓库同步至 WebDAV 服务器是一个典型的<strong>去中心化协调</strong>问题：每个客户端拥有自己的仓库副本，且中间没有中央协调器。目标是在各客户端之间实现仓库同步，以最大化数据完整性。</p><p>为此，本插件记录了本地和远程文件的最后一次已知同步状态。在同步过程中，它会评估每个文件路径的<strong>四种状态</strong>（当前本地、当前远程、记录中的本地、记录中的远程），并据此决定同步操作：</p><blockquote><p>✅ = 存在，❌ = 不存在，✏️ = 相比记录已变更</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">情况</th><th style="text-align:center;">本地文件</th><th style="text-align:center;">远程文件</th><th style="text-align:center;">同步记录</th><th style="text-align:left;">操作</th></tr></thead><tbody><tr><td style="text-align:left;">1</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:left;">⏭️ <strong>跳过</strong> (已同步)</td></tr><tr><td style="text-align:left;">2</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td style="text-align:left;">⚠️ <strong>解决冲突</strong> (应用策略)</td></tr><tr><td style="text-align:left;">3</td><td style="text-align:center;">✅</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td style="text-align:left;">⬇️ <strong>拉取</strong> (下载远程)</td></tr><tr><td style="text-align:left;">4</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:left;">⬆️ <strong>推送</strong> (上传本地)</td></tr><tr><td style="text-align:left;">5</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:left;">🗑️ <strong>删除本地</strong> (清理)</td></tr><tr><td style="text-align:left;">6</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:left;">🗑️ <strong>删除远程</strong> (清理)</td></tr><tr><td style="text-align:left;">7</td><td style="text-align:center;">❌</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td style="text-align:left;">⬇️ <strong>拉取</strong> (从远程恢复)</td></tr><tr><td style="text-align:left;">8</td><td style="text-align:center;">✏️</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:left;">⬆️ <strong>推送</strong> (恢复到远程)</td></tr><tr><td style="text-align:left;">9</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅ (对比本地)</td><td style="text-align:center;">❌</td><td style="text-align:left;">📝 <strong>记录</strong> (捕获未记录的文件)</td></tr><tr><td style="text-align:left;">10</td><td style="text-align:center;">✅</td><td style="text-align:center;">✏️ (对比本地)</td><td style="text-align:center;">❌</td><td style="text-align:left;">⚠️ <strong>解决冲突</strong> (首次同步)</td></tr><tr><td style="text-align:left;">11</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:left;">⬇️ <strong>拉取</strong> (新远程文件)</td></tr><tr><td style="text-align:left;">12</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:left;">⬆️ <strong>推送</strong> (新本地文件)</td></tr><tr><td style="text-align:left;">13</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:left;">🧹 <strong>清理记录</strong> (数据库清理)</td></tr></tbody></table><p>现在的同步逻辑已足够可靠，但也引发了一些新问题。</p><p>例如，同步前比较四种状态意味着每次同步开始时都需要对 <strong>整个 WebDAV、本地仓库和记录进行遍历</strong>，这对于大型仓库来说是不切实际的。为此，引入了<strong>快速模式 (Fast Mode)</strong>，它复用记录中的远程状态作为当前状态。这避免了遍历整个 WebDAV，但会忽略远程端的变更。因此，<strong>建议在快速同步前先进行一次普通同步</strong>。</p><p>此外，存储所有文件的记录和内容为比对文件是否变更，需要大量且活跃的存储空间来确保保真度。本插件利用 IndexedDB 存储记录，并按需查询。</p><p>随之而来的还有更多问题：如果在遍历和执行期间文件发生了变化怎么办？如果远程端文件变成了文件夹怎么办？如果后续对存储结构进行修改，如何迁移用户数据？这些问题都值得深入探讨。</p><h2 id="安装与设置" tabindex="-1">安装与设置 <a class="header-anchor" href="#安装与设置" aria-label="Permalink to “安装与设置”">​</a></h2><p>由于该插件目前处于 Beta 阶段，安装需要使用 <strong>BRAT</strong> (Beta Reviewer Auto-update Tool) 插件：</p><h3 id="步骤-1-安装-brat" tabindex="-1">步骤 1：安装 BRAT <a class="header-anchor" href="#步骤-1-安装-brat" aria-label="Permalink to “步骤 1：安装 BRAT”">​</a></h3><ol><li>打开 Obsidian 设置 → 社区插件</li><li>搜索并安装 <strong>BRAT</strong></li><li>启用该插件</li></ol><h3 id="步骤-2-添加-obsidian-webdav-sync" tabindex="-1">步骤 2：添加 Obsidian WebDAV Sync <a class="header-anchor" href="#步骤-2-添加-obsidian-webdav-sync" aria-label="Permalink to “步骤 2：添加 Obsidian WebDAV Sync”">​</a></h3><ol><li>打开 BRAT 设置</li><li>点击 <strong>Add beta plugin</strong> (添加测试版插件)</li><li>粘贴仓库地址：<code>https://github.com/hesprs/obsidian-webdav-sync</code></li><li>选择最新版本并点击 <strong>Add plugin</strong> (添加插件)</li></ol><h3 id="步骤-3-配置-webdav-连接" tabindex="-1">步骤 3：配置 WebDAV 连接 <a class="header-anchor" href="#步骤-3-配置-webdav-连接" aria-label="Permalink to “步骤 3：配置 WebDAV 连接”">​</a></h3><ol><li>输入您的 WebDAV 服务器地址</li><li>提供账户凭据</li><li>点击 <strong>Check connection</strong> (检查连接) 进行验证</li><li>选择您的远程目录</li><li>启动首次同步</li></ol><blockquote><p>在首次同步前，请务必备份重要笔记。虽然该插件能稳健地处理文件存在性判定，但在首次设置时拥有备份能让您更加安心。</p></blockquote><h2 id="开源协议" tabindex="-1">开源协议 <a class="header-anchor" href="#开源协议" aria-label="Permalink to “开源协议”">​</a></h2><p>Obsidian WebDAV Sync 采用 <a href="https://www.gnu.org/licenses/agpl-3.0.en.html" target="_blank" rel="noreferrer">AGPL-3.0 许可证</a> 发布。</p>',27)])]))}});export{y as __pageData,x as default};
